// // This module generates a write enable signal (we) based on the input packet (pkti). The output we is asserted low if both the 9th and 8th bits of pkti are high.
module top_module(pkti, we);(* src = "mkwe.v:1" *)
  input [9:0] pkti;
  (* src = "mkwe.v:1" *)
  output we;
  assign we = pkti[9] | pkti[8];endmodule
